import { Vex } from '@vex_dev/sdk';
import { ChatFlow } from 'flowise';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  projectId: 'legal-flowise-app'
});

const legalPolicy = {
  name: 'ABA-Compliance',
  rules: [
    { type: 'hallucination_check', threshold: 0.8, domains: ['caselaw'] },
    { type: 'pii_redact', entities: ['client_name', 'case_number'] },
    { type: 'citation_verify', sources: ['westlaw', 'lexis'] }
  ]
};

// Add to Flowise chatflow config
const chatflow = new ChatFlow();
chatflow.addCallback('afterChain', async (input, output) => {
  const result = await vex.validate({
    input,
    output,
    policy: legalPolicy,
    context: { industry: 'legal', privilege: true }
  });
  if (!result.compliant) {
    throw new Error(`Compliance failure: ${result.violations.join(', ')}`);
  }
  return output;
});

const vectorGuard = async (docs: Document[]) => {
  const results = await vex.validate({
    input: { query: chatflow.query },
    output: { documents: docs },
    policy: {
      name: 'RAG-Legal',
      rules: [
        {
          type: 'semantic_relevance',
          threshold: 0.75,
          metadata: { privilege: 'blocked' }
        },
        { type: 'privilege_scan', block: true }
      ]
    }
  });

  return results.compliant ? docs.filter(d => d.relevance > 0.75) : [];
};

// Hook into Flowise vector store node
chatflow.vectorStore.on('retrieve', vectorGuard);

const agentHandoffGuard = async (fromAgent: string, toAgent: string, context: any) => {
  const handoffCheck = await vex.validate({
    input: { from: fromAgent, to: toAgent },
    output: context,
    policy: {
      name: 'Agent-Handoff',
      rules: [
        { type: 'context_preservation', required: ['privilege_flags', 'citations'] },
        { type: 'chain_of_thought', min_steps: 3 }
      ]
    }
  });

  if (!handoffCheck.compliant) {
    console.warn('Context loss detected:', handoffCheck.violations);
    return { ...context, review_required: true };
  }
  return context;
};

chatflow.on('agentHandoff', agentHandoffGuard);
